#include <bits/stdc++.h>
using namespace std;

const int N=1e6+10;

struct Node{
    int l,r,id;
    bool operator<(Node x)const{return r<x.r;}
}q[N];

int n,m,a[N],c[N],lst[N],ans[N];

void add(int x,int k){
	for(;x<=n;x+=(x&(-x)))
		c[x]+=k;
}

int ask(int x){
	int res=0;
	for(;x;x-=(x&(-x)))
		res+=c[x];
	return res;
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    scanf("%d",&m);
    for(int i=1;i<=m;i++){
        scanf("%d%d",&q[i].l,&q[i].r);
        q[i].id=i;
    }
    sort(q+1,q+m+1);
    for(int i=1,r=1;i<=m;i++){
        while(r<=q[i].r){
            if(lst[a[r]])
                add(lst[a[r]],-1);
            add(r,1);
            lst[a[r]]=r; 
            r++;
        }
        ans[q[i].id]=ask(q[i].r)-ask(q[i].l-1);
    }
    for(int i=1;i<=m;i++)
        printf("%d\n",ans[i]);
    return 0;
}
